import { useEffect, useState } from "react";
import axios from "../api/axios";

export default function AdminDashboard() {
  const [stats, setStats] = useState({ totalSlots: 0, activeBookings: 0, availableSlots: 0 });
  const [bookings, setBookings] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchData();
    const interval = setInterval(fetchData, 30000); // Poll every 30s
    return () => clearInterval(interval);
  }, []);

  const fetchData = async () => {
    try {
      const statsRes = await axios.get("/bookings/stats");
      setStats(statsRes.data);

      const bookingsRes = await axios.get("/bookings");
      setBookings(bookingsRes.data);
      setLoading(false);
    } catch (err) {
      console.error("Failed to fetch admin data", err);
      // If 403, maybe redirect to login?
    }
  };

  if (loading) return <div className="container" style={{ textAlign: 'center', marginTop: '50px' }}>Loading Dashboard...</div>;

  return (
    <div className="container">
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px' }}>
        <h2>🛡️ Admin Dashboard</h2>
        <button className="btn-primary" onClick={fetchData} style={{ padding: '8px 15px', fontSize: '0.9rem' }}>🔄 Refresh</button>
      </div>

      {/* STATS CARDS */}
      <div className="grid" style={{ gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))', marginBottom: '30px' }}>
        <div className="card" style={{ textAlign: 'center', borderTop: '4px solid #3498db' }}>
          <h3 style={{ fontSize: '2.5rem', margin: '10px 0', color: '#3498db' }}>{stats.totalSlots}</h3>
          <p style={{ color: '#aaa' }}>Total Parking Slots</p>
        </div>
        <div className="card" style={{ textAlign: 'center', borderTop: '4px solid #e74c3c' }}>
          <h3 style={{ fontSize: '2.5rem', margin: '10px 0', color: '#e74c3c' }}>{stats.activeBookings}</h3>
          <p style={{ color: '#aaa' }}>Active Reservations</p>
        </div>
        <div className="card" style={{ textAlign: 'center', borderTop: '4px solid #2ecc71' }}>
          <h3 style={{ fontSize: '2.5rem', margin: '10px 0', color: '#2ecc71' }}>{stats.availableSlots}</h3>
          <p style={{ color: '#aaa' }}>Available Slots</p>
        </div>
      </div>

      {/* BOOKINGS TABLE */}
      <div className="card">
        <h3>📋 Live Reservation Log</h3>
        <div style={{ overflowX: 'auto' }}>
          <table style={{ width: '100%', borderCollapse: 'collapse', marginTop: '15px' }}>
            <thead>
              <tr style={{ background: 'var(--bg-tertiary)', textAlign: 'left' }}>
                <th style={{ padding: '12px', borderBottom: '2px solid #444' }}>User</th>
                <th style={{ padding: '12px', borderBottom: '2px solid #444' }}>Vehicle</th>
                <th style={{ padding: '12px', borderBottom: '2px solid #444' }}>Location</th>
                <th style={{ padding: '12px', borderBottom: '2px solid #444' }}>Time Range</th>
                <th style={{ padding: '12px', borderBottom: '2px solid #444' }}>Status</th>
              </tr>
            </thead>
            <tbody>
              {bookings.length > 0 ? bookings.map(b => (
                <tr key={b._id} style={{ borderBottom: '1px solid #333' }}>
                  <td style={{ padding: '12px' }}>
                    <div style={{ fontWeight: 'bold' }}>{b.userId?.name || 'Unknown'}</div>
                    <div style={{ fontSize: '0.8rem', color: '#888' }}>{b.userId?.email}</div>
                  </td>
                  <td style={{ padding: '12px' }}>
                    <div style={{ fontWeight: 'bold', color: '#fff' }}>{b.vehicleNumber}</div>
                    <div style={{ fontSize: '0.8rem', color: '#aaa' }}>{b.vehicleType}</div>
                  </td>
                  <td style={{ padding: '12px' }}>
                    {b.slotId ? (
                      <>
                        <div>{b.slotId.parkingLotId?.name || 'Unknown Lot'}</div>
                        {/* Note: slotId.parkingLotId might be an ID if not populated deep enough. 
                             bookingController uses populate("slotId"). 
                             Slot model ref to ParkingLot? 
                             Let's check if we need deep populate. 
                             For now assume slotId has parkingLotId populated? 
                             Actually bookingController just does populate("slotId"). 
                             If Slot schema has ref to ParkingLot, we need deep populate to get Name. 
                             Or update controller.
                         */}
                        <span style={{ background: '#34495e', padding: '2px 6px', borderRadius: '4px', fontSize: '0.8rem' }}>
                          Slot {b.slotId.slotNumber}
                        </span>
                      </>
                    ) : <span style={{ color: 'red' }}>Slot Deleted</span>}
                  </td>
                  <td style={{ padding: '12px' }}>
                    <div style={{ fontSize: '0.9rem' }}>{new Date(b.startTime).toLocaleString()}</div>
                    <div style={{ fontSize: '0.9rem', color: '#888' }}>to {new Date(b.endTime).toLocaleString()}</div>
                  </td>
                  <td style={{ padding: '12px' }}>
                    <span style={{
                      background: b.status === 'Active' ? 'rgba(46, 204, 113, 0.2)' : 'rgba(149, 165, 166, 0.2)',
                      color: b.status === 'Active' ? '#2ecc71' : '#95a5a6',
                      padding: '4px 8px', borderRadius: '4px', fontWeight: 'bold', fontSize: '0.85rem'
                    }}>
                      {b.status}
                    </span>
                  </td>
                </tr>
              )) : (
                <tr>
                  <td colSpan="5" style={{ padding: '20px', textAlign: 'center', color: '#777' }}>No active bookings found.</td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}
